class Solution(object):
    def countPathsWithXorValue(self, grid, k):
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])
        # dp[i][j][x] = number of paths to (i,j) with XOR value x
        # x can be 0..15 since grid values < 16 and k < 16
        dp = [[[0] * 16 for _ in range(n)] for _ in range(m)]
        dp[0][0][grid[0][0]] = 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                for x in range(16):
                    ways = 0
                    if i > 0:
                        ways += dp[i-1][j][x ^ grid[i][j]]
                    if j > 0:
                        ways += dp[i][j-1][x ^ grid[i][j]]
                    dp[i][j][x] = ways % MOD
        return dp[m-1][n-1][k]
